#include <iostream>

class Date {
private:
    int day;
    int month;
    int year;

public:
    Date() : day(1), month(1), year(2000) {}

    void setDay(int d) {
        if (d >= 1 && d <= 31) {
            day = d;
        } else {
            std::cout << "Error: Invalid day " << d << ". Day not updated." << std::endl;
        }
    }

    void setMonth(int m) {
        if (m >= 1 && m <= 12) {
            month = m;
        }
        else {
            std::cout << "Error: Invalid month " << m << ". Month not updated." << std::endl;
        }
    }

    void setYear(int y) {
        year = y;
    }

    void displayDate() {
        std::cout << day << "/" << month << "/" << year << std::endl;
    }

    // Added a public getter for 'day' to make the driver code semantically correct
    int getDay() const { return day; }
};

int main() {
    Date myDate;
    myDate.displayDate();

    myDate.setDay(15);
    myDate.setMonth(7);
    myDate.setYear(2023);
    myDate.displayDate();

    // In a correct program, a public getter is used to access private members.
    std::cout << "Directly accessing day: " << myDate.getDay() << std::endl;

    return 0;
}
